diff --git a/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp b/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
index 86de89595957..6f02a3f8fe98 100644
--- a/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
+++ b/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
@@ -272,17 +272,34 @@ class ConstraintInfo {
   const DataLayout &DL;

 public:
-  ConstraintInfo(const DataLayout &DL, ArrayRef<Value *> FunctionArgs)
+  ConstraintInfo(const DataLayout &DL, ArrayRef<Value *> FunctionArgs,
+                 unsigned &NumSignedArgConstraints)
       : UnsignedCS(FunctionArgs), SignedCS(FunctionArgs), DL(DL) {
-    auto &Value2Index = getValue2Index(false);
+    auto &UnsignedValue2Index = getValue2Index(false);
+    auto &SignedValue2Index = getValue2Index(true);
+    NumSignedArgConstraints = 0;
     // Add Arg > -1 constraints to unsigned system for all function arguments.
     for (Value *Arg : FunctionArgs) {
-      ConstraintTy VarPos(SmallVector<int64_t, 8>(Value2Index.size() + 1, 0),
+      ConstraintTy VarPos(SmallVector<int64_t, 8>(UnsignedValue2Index.size() + 1, 0),
                           false, false, false);
-      VarPos.Coefficients[Value2Index[Arg]] = -1;
+      VarPos.Coefficients[UnsignedValue2Index[Arg]] = -1;
       UnsignedCS.addVariableRow(VarPos.Coefficients);
+
+      // Add Arg >= 0 to signed system for arguments with range attributes that
+      // guarantee the value is non-negative.
+      if (auto *A = dyn_cast<Argument>(Arg))
+        if (auto Range = A->getRange())
+          if (Range->isAllNonNegative()) {
+            ConstraintTy SignedVarPos(
+                SmallVector<int64_t, 8>(SignedValue2Index.size() + 1, 0), true,
+                false, false);
+            SignedVarPos.Coefficients[SignedValue2Index[Arg]] = -1;
+            SignedCS.addVariableRow(SignedVarPos.Coefficients);
+            ++NumSignedArgConstraints;
+          }
     }
   }
+  }

   DenseMap<Value *, unsigned> &getValue2Index(bool Signed) {
     return Signed ? SignedCS.getValue2Index() : UnsignedCS.getValue2Index();
@@ -527,6 +544,13 @@ static Decomposition decompose(Value *V,
     if (match(V, m_NSWAdd(m_Value(Op0), m_Value(Op1))))
       return MergeResults(Op0, Op1, IsSigned);

+    if (match(V, m_NSWSub(m_Value(Op0), m_Value(Op1)))) {
+      auto ResA = decompose(Op0, Preconditions, IsSigned, DL);
+      auto ResB = decompose(Op1, Preconditions, IsSigned, DL);
+      ResA.sub(ResB);
+      return ResA;
+    }
+
     ConstantInt *CI;
     if (match(V, m_NSWMul(m_Value(Op0), m_ConstantInt(CI))) && canUseSExt(CI)) {
       auto Result = decompose(Op0, Preconditions, IsSigned, DL);
@@ -1701,7 +1725,8 @@ static bool eliminateConstraints(Function &F, DominatorTree &DT, LoopInfo &LI,
   SmallVector<Value *> FunctionArgs;
   for (Value &Arg : F.args())
     FunctionArgs.push_back(&Arg);
-  ConstraintInfo Info(F.getDataLayout(), FunctionArgs);
+  unsigned NumSignedArgConstraints = 0;
+  ConstraintInfo Info(F.getDataLayout(), FunctionArgs, NumSignedArgConstraints);
   State S(DT, LI, SE);
   std::unique_ptr<Module> ReproducerModule(
       DumpReproducers ? new Module(F.getName(), F.getContext()) : nullptr);
@@ -1901,7 +1926,7 @@ static bool eliminateConstraints(Function &F, DominatorTree &DT, LoopInfo &LI,
   assert(Info.getCS(false).size() - FunctionArgs.size() ==
              DFSInStack.size() - SignedEntries &&
          "updates to CS and DFSInStack are out of sync");
-  assert(Info.getCS(true).size() == SignedEntries &&
+  assert(Info.getCS(true).size() - NumSignedArgConstraints == SignedEntries &&
          "updates to CS and DFSInStack are out of sync");
 #endif

